// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// THÊM MỚI: Import dữ liệu loài để gợi ý
import speciesData from '../data/speciesData';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',
    scientificName: '', // THÊM MỚI: State cho tên khoa học
    date: '',
    // ... các trường khác giữ nguyên
  });

  // THÊM MỚI: State để điều khiển giao diện động
  const [isManualEntry, setIsManualEntry] = useState(false);

  const fetchFarmDetails = useCallback(async () => {
    // ... logic fetchFarmDetails giữ nguyên
  }, [farmId, token, navigate]);

  useEffect(() => {
    if (farmId && token) {
      fetchFarmDetails();
    }
    // ... logic useEffect khác giữ nguyên
  }, [farmId, token, navigate, fetchFarmDetails]);

  // CẬP NHẬT: Nâng cấp hàm xử lý thay đổi của form
  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;

    // Xử lý riêng cho dropdown speciesName
    if (name === 'speciesName') {
      if (value === 'manual') {
        setIsManualEntry(true);
        // Xóa tên loài và tên khoa học khi chuyển sang nhập tay
        setActivityFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
      } else {
        setIsManualEntry(false);
        // Tìm trong cả danh sách của farm và danh sách gợi ý
        const allSpecies = [...(farm?.loaiDongVatRung || []), ...speciesData];
        const matched = allSpecies.find(s => s.tenLamSan === value);
        setActivityFormData(prev => ({
          ...prev,
          speciesName: value,
          scientificName: matched ? matched.tenKhoaHoc : ''
        }));
      }
    } else {
      // Xử lý cho các ô input khác
      let newFormData = { ...activityFormData };
      if (['date', 'reasonForChange', 'scientificName'].includes(name)) {
        newFormData[name] = value;
      } else {
        const [mainField, subField, prop] = name.split('.');
        newFormData = {
          ...newFormData,
          [mainField]: {
            ...newFormData[mainField],
            [subField]: {
              ...newFormData[mainField][subField],
              [prop]: parseInt(value, 10) || 0,
            },
          },
        };
      }
      setActivityFormData(newFormData);
    }
  };


  const handleAddActivity = async (e) => {
    // ... logic handleAddActivity giữ nguyên
  };

  const handleDeleteActivity = async (activityId) => {
    // ... logic handleDeleteActivity giữ nguyên
  };

  if (loading) { /* ... */ }
  if (error) { /* ... */ }
  if (!farm) { /* ... */ }

  return (
    <div className="form-container">
      {/* ... style và tiêu đề giữ nguyên ... */}

      <div className="form-grid">
        <div className="detail-group">
          <strong>Farm Name:</strong> <p>{farm.tenCoSo}</p>
        </div>
        <div className="detail-group">
          <strong>Address:</strong> <p>{farm.diaChiCoSo}</p>
        </div>
        <div className="form-group detail-group">
          <label>Species Name:</label>
          <select
            name="speciesName"
            value={isManualEntry ? 'manual' : activityFormData.speciesName}
            onChange={handleActivityFormChange}
            required
          >
            <option value="">-- Select or enter manually --</option>
            {/* Nhóm các loài đã có của cơ sở */}
            <optgroup label="Loài đã có tại cơ sở">
              {farm.loaiDongVatRung && farm.loaiDongVatRung.map((species, index) => (
                <option key={`farm-${index}`} value={species.tenLamSan}>
                  {species.tenLamSan}
                </option>
              ))}
            </optgroup>
            {/* Nhóm các loài gợi ý */}
            <optgroup label="Gợi ý các loài khác">
              {speciesData.map((species, index) => (
                <option key={`data-${index}`} value={species.tenLamSan}>
                  {species.tenLamSan}
                </option>
              ))}
            </optgroup>
            <option value="manual">--- Nhập thủ công... ---</option>
          </select>
        </div>
      </div>

      {/* THÊM MỚI: Khu vực nhập tay, chỉ hiện khi cần */}
      {isManualEntry && (
        <div className="form-grid manual-entry-box">
          <div className="form-group">
            <label>Tên loài (nhập tay):</label>
            <input
              type="text"
              name="speciesName"
              value={activityFormData.speciesName}
              onChange={handleActivityFormChange}
              placeholder="Nhập tên loài mới..."
              required
            />
          </div>
          <div className="form-group">
            <label>Tên khoa học (nhập tay):</label>
            <input
              type="text"
              name="scientificName"
              value={activityFormData.scientificName}
              onChange={handleActivityFormChange}
              placeholder="Nhập tên khoa học..."
            />
          </div>
        </div>
      )}

      <h3>Add New Tracking Record:</h3>
      {/* ... phần còn lại của form và bảng giữ nguyên ... */}

    </div>
  );
}

export default FarmDetail;
